public class Adler32 {
    public static long computeAdler32(byte[] data) {
        long a = 1, b = 0;
        final int MOD_ADLER = 65521;

        for (byte d : data) {
            // Ensure byte is treated as unsigned
            a = (a + (d & 0xFF)) % MOD_ADLER;
            b = (b + a) % MOD_ADLER;
        }

        return (b << 16) | a;
    }
}
